const staticData = $getWorkflowStaticData('global');
const items = $input.all();
let competitions = [];
for (const item of items) {
  const j = item.json;
  if (Array.isArray(j)) competitions = competitions.concat(j);
  else if (j.competitionId) competitions.push(j);
  else { for (const k of Object.keys(j)) { if (Array.isArray(j[k])) { competitions = competitions.concat(j[k]); break; } } }
}
staticData.competitions = JSON.stringify(competitions);
return [{json: {step: '1_competitions', count: competitions.length}}];

