const staticData = $getWorkflowStaticData('global');
const items = $input.all();
let evaluations = [];
for (const item of items) {
  const j = item.json;
  if (Array.isArray(j)) evaluations = evaluations.concat(j);
  else if (j.evaluationId !== undefined) evaluations.push(j);
  else { for (const k of Object.keys(j)) { if (Array.isArray(j[k])) { evaluations = evaluations.concat(j[k]); break; } } }
}
staticData.evaluations = JSON.stringify(evaluations);
return [{json: {step: '4_evaluations', count: evaluations.length}}];

// Renomear arquivo para relatorio-avaliacoes-DD-MM-YYYY.xlsx
const items = $input.all();
for (const item of items) {
  if (item.binary && item.binary.data) {
    const now = new Date();
    const dd = String(now.getDate()).padStart(2, '0');
    const mm = String(now.getMonth() + 1).padStart(2, '0');
    const yyyy = now.getFullYear();
    item.binary.data.fileName = `relatorio-avaliacoes-${dd}-${mm}-${yyyy}.xlsx`;
  }
}
return items;

const staticData = $getWorkflowStaticData('global');
const items = $input.all();
let allRows = [];
for (const item of items) {
  const j = item.json;
  if (j.rows && Array.isArray(j.rows)) allRows = allRows.concat(j.rows);
  else if (j.farm && j.territory) allRows.push(j);
}
// Build farm name -> territory map
const terrMap = {};
for (const row of allRows) {
  const farmName = (row.farm && row.farm.name) ? row.farm.name.trim() : '';
  const territory = (row.territory && row.territory.name) ? row.territory.name : '';
  if (farmName && territory) terrMap[farmName] = territory;
}
staticData.territories = JSON.stringify(terrMap);
return [{json: {step: '5_territories', count: Object.keys(terrMap).length}}];
